def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character into a fluent sentence.
    """
    if not triples:
        return ""

    # Helper to generate a phrase for a triple (including the subject)
    def _make_phrase(s: str, pred: str, o: str) -> str:
        pred = pred.lower()
        o = o.strip('"\'')
        def _singular(val: str) -> str:
            if val.endswith('s') and not val.endswith('ss') and ' ' not in val:
                return val[:-1]
            return val
        if pred == "alternativename":
            return f"{s} is also known as {o}"
        if pred == "creator":
            return f"{s} was created by {o}"
        if pred == "fullname":
            return f"{s}'s full name is {o}"
        if pred == "foundedby":
            return f"{s} was founded by {o}"
        if pred == "keyperson":
            return f"{o} is a key person at {s}"
        if pred == "city":
            return f"{s} is located in {o}"
        if pred == "product":
            return f"{s} produces {o}"
        if pred == "lastaired":
            return f"The last episode of {s} aired on {o}"
        if pred == "starring":
            return f"{s} stars {o}"
        if pred == "firstappearanceinfilm":
            return f"{s} first appeared in the film {o}"
        if pred == "voice":
            return f"{o} provides the voice for {s}"
        if pred == "distributor":
            return f"{o} distributed {s}"
        if pred == "birthplace":
            return f"{s} was born in {o}"
        if pred == "nationality":
            return f"{s} is {_singular(o)}"
        if pred == "award":
            return f"{s} received the {o}"
        if pred == "broadcastedby":
            return f"{s} was broadcast by {o}"
        if pred == "firstaired":
            return f"{s} first aired on {o}"
        if pred == "series":
            return f"{s} is part of the series {o}"
        if pred == "child":
            return f"{s} has a child named {o}"
        return f"{s} {pred} {o}"

    # Group triples by their subject to allow relative‑clause combination
    from collections import defaultdict
    groups = defaultdict(list)
    for triple in triples:
        groups[triple.subject].append(triple)

    combined_clauses = []
    for subj, triples_list in groups.items():
        # Build the main clause from the first triple
        first = triples_list[0]
        main_phrase = _make_phrase(first.subject, first.predicate, first.object)

        # Build relative clauses for any remaining triples of the same subject
        rel_parts = []
        for extra in triples_list[1:]:
            full = _make_phrase(extra.subject, extra.predicate, extra.object)
            # Remove the leading subject and following space
            suffix = full[len(extra.subject):].lstrip()
            # Prefix with a relative connector
            rel_parts.append(f"which {suffix}")

        if rel_parts:
            # Join multiple relative parts with commas and 'and' before the last
            if len(rel_parts) == 1:
                clause = f"{main_phrase}, {rel_parts[0]}"
            else:
                clause = f"{main_phrase}, " + ", ".join(rel_parts[:-1]) + f", and {rel_parts[-1]}"
        else:
            clause = main_phrase

        combined_clauses.append(clause)

    # Join all subject clauses into one sentence
    if not combined_clauses:
        return ""
    if len(combined_clauses) == 1:
        return combined_clauses[0] + "."
    if len(combined_clauses) == 2:
        return f"{combined_clauses[0]} and {combined_clauses[1]}."
    return f"{', '.join(combined_clauses[:-1])}, and {combined_clauses[-1]}."

